<!-- eslint-disable vuejs-accessibility/click-events-have-key-events -->
<template>
  <div class="bg-light">
    <div class="d-flex justify-content-center">
      <div>
        <b-button @click="resetState()">Reset</b-button>
      </div>
      <div>
        <b-button @click="print"> Print </b-button>
      </div>
    </div>
    <div
      class="main-form bg-white shadow-md p-2 pb-5"
      id="resume-form"
      style="margin: 0 auto; width: calc(100% - 300px)"
      :class="`font-${currentFont.value}`"
    >
      <span v-html="`<style>${styleFormPrint}</style>`" />
      <span v-html="includeFotns"></span>
      <div :class="isActiveContainerClass('main-info')" @click="setActiveContainer('main-info')">
        <ContainerFocusItem
          :is-active="isActiveContainer('main-info')"
          @set-focus="setActiveContainer"
          name="main-info"
        >
        <template v-slot="{ isFocus }">
            <div class="p-2">
              <div class="d-flex">
                <div :class="{ 'w-100': !formData.imgDataUrl }">
                  <b-form-input
                    class="text-center"
                    :style="nameInputsStyle"
                    v-model="fullName"
                    placeholder="Your full name"
                    @change="updateInputValue"
                  />
                  <b-form-input
                    v-model="position"
                    class="text-center"
                    :style="positionInputsStyle"
                    placeholder="Your position"
                    @change="updateInputValue"
                  />
                </div>
                <div>
                  <PhotoInput :isStatic="!isFocus" />
                </div>
              </div>
              <div class="pt-4">
                <ContactInput :value="formData.contacts" :is-focus="isFocus" />
              </div>
            </div>
          </template>
        </ContainerFocusItem>
      </div>
      <draggable v-model="mainFormInputs">
        <transition-group>
          <div
            v-for="(input, inputKey) in mainFormInputs"
            :key="`input-${inputKey}`"
            :class="isActiveContainerClass(`${input.type}-${input.id}`)"
            @click="setActiveContainer(`${input.type}-${input.id}`)"
          >
            <ContainerFocusItem
              :name="`${input.type}-${input.id}`"
              @set-focus="setActiveContainer"
              :is-active="isActiveContainer(`${input.type}-${input.id}`)"
            >
              <template v-slot="{ isFocus }">
                <div>
                  <div>
                    <title-container
                      :id="input.id"
                      :text="getContainerTitleValue(input.id)"
                      :placeholder="input.name"
                    />
                    <div>
                      <div class="position-relative">
                        <component
                          :id="input.id"
                          :value="getValue(input.id)"
                          :isFocus="isFocus"
                          v-bind:is="input.component"
                        />
                        <b-button
                          v-show="isFocus"
                          size="sm"
                          @click="deleteInputForm(input)"
                          variant="danger"
                          class="position-absolute"
                          style="top: -20px; right: -20px;"
                        >
                          <b-icon icon="trash" />
                        </b-button>
                      </div>
                    </div>
                  </div>
                </div>
              </template>
            </ContainerFocusItem>
          </div>
        </transition-group>
      </draggable>
    </div>
  </div>
</template>

<script>
import { mapGetters, mapState, mapMutations } from 'vuex';
import types from '@/store/modules/form/types';
import formMixin from '@/mixins/form';
import ContactStaticItem from '@/components/StaticItem/ContactStaticItem.vue';
import TitleContainer from '@/components/TitleContainer.vue';
import TextPlaceholder from '@/components/TextPlaceholder.vue';
import draggable from 'vuedraggable';
import BaseDatepickerRange from '@/components/core/BaseDatepickerRange.vue';
import ContactInput from './ContactInput.vue';
import PhotoInput from './PhotoInput.vue';
import ContainerFocusItem from './ContainerFocusItem.vue';

export default {
  name: 'MainForm',
  components: {
    ContactInput,
    PhotoInput,
    ContainerFocusItem,
    TitleContainer,
    TextPlaceholder,
    ContactStaticItem,
    draggable,
    BaseDatepickerRange,
  },
  mixins: [formMixin],
  data() {
    return {
      fullName: '',
      position: '',
      skills: ['name - skill'],
      expirience: [{ companyName: '', date: 'YYYY-MM', description: '' }],
      education: [{ placeName: '', date: 'YYYY', description: '' }],
      about: '',
      properties: ['fullName', 'position', 'about'],
      mainFormInputs: null,
      activeContainer: '',
    };
  },
  computed: {
    ...mapState('form', [
      'inputs',
      'formData',
      'currentColor',
      'currentFont',
    ]),
    ...mapGetters('form', [
      'getValue',
      'getContainerTitleValue',
      'styleFormPrint',
      'includeFotns',
    ]),
    ...mapState('form', ['currentColor', 'currentFont']),
    nameInputsStyle() {
      return `
      font-size: 2.5rem; border-style: none;
      color: ${this.currentColor.style};
      font-family: ${this.currentFont.style};
      `;
    },
    positionInputsStyle() {
      return `
      font-size: calc(1.275rem + 0.3vw); border-style: none;
      font-family: ${this.currentFont.style};
      `;
    },
  },
  watch: {
    inputs: {
      immediate: true,
      handler() {
        this.mainFormInputs = this.inputs;
      },
    },
    mainFormInputs() {
      this.updateInputs(this.mainFormInputs);
    },
  },
  methods: {
    ...mapMutations('form', {
      updateInputs: types.SET_INPUT,
      deleteInputForm: types.DELETE_INPUT_FROM_AND_DATA,
      initState: types.INIT_STATE,
      resetState: types.RESET_STATE,
      setPrintState: types.PRINT_MODE_STATE,
    }),
    async print() {
      this.setPrintState(true);
      setTimeout(async () => {
        await this.$htmlToPaper(
          'resume-form',
          null,
          () => this.setPrintState(false),
        );
      }, 100);
    },
    setActiveContainer(activeContainer = '') {
      if (activeContainer) {
        setTimeout(() => {
          this.activeContainer = activeContainer;
        }, 50);
      } else {
        this.activeContainer = activeContainer;
      }
    },
    isActiveContainer(containerName) {
      return containerName === this.activeContainer;
    },
    isActiveContainerClass(containerName) {
      if (!this.activeContainer) return 'active';
      return this.isActiveContainer(containerName) ? 'active shadow-lg' : 'disable-container';
    },
  },
  mounted() {
    this.initState();
  },
};
</script>
<style lang="scss">
@import '../assets/app.scss';
.disable-container {
  position: relative;
  &:after {
    content: ' ';
    position: absolute;
    top: 0px;
    left: 0px;
    height: 100%;
    width: 100%;
    background-color: #e6e6e66e;
    z-index: 90;
  }
}
</style>
