<template>
  <div class="conatct-input">
    <b-row class="justify-content-center">
      <b-col cols="4" v-for="(contact, index) in contacts" :key="index">
        <div class="d-flex align-items-center justify-content-center">
          <div class="contatc-icon">
            <div class="icon-wrapper d-flex">
              <div class="icon">
                <base-icon-selector :isStatic="!isFocus" />
              </div>
            </div>
          </div>
          <div class="contatc-input pl-4">
            <base-input
              v-model="contacts[index].value"
              placeholder="Your contact"
              @change="updateInputValue()"
            />
          </div>
          <div v-show="isFocus">
            <b-icon icon="trash-fill" @click="deleteConatct(index)" />
          </div>
        </div>
      </b-col>
      <b-col v-show="isFocus">
        <div class="d-flex align-item-center">
          <b-button size="sm" variant="dark-outline" @click="addConatct">
            add <b-icon icon="plus-lg" />
          </b-button>
        </div>
      </b-col>
    </b-row>
  </div>
</template>

<script>
import { mapMutations } from 'vuex';
import cloneDepp from 'lodash/cloneDeep';
import formMixin from '@/mixins/form';
import BaseInput from '@/components/core/BaseInput.vue';
import BaseIconSelector from '@/components/core/BaseIconSelector.vue';
import * as types from '@/store/modules/form/types';

const defaultSkill = { icon: 'phone', value: '' };

export default {
  name: 'ConatactInput',
  components: { BaseInput, BaseIconSelector },
  mixins: [formMixin],
  props: {
    id: {
      type: String,
      require: true,
      default: '',
    },
    value: {
      type: Array,
      require: true,
      default: () => [],
    },
    isFocus: {
      type: Boolean,
      require: true,
      default: false,
    },
  },
  data() {
    return {
      contacts: this.value,
      properties: ['contacts'],
      focus: false,
    };
  },
  methods: {
    ...mapMutations('form', { setFormProperty: types.SET_FORM_PROPERTY }),
    addConatct() {
      this.contacts = [...(this.contacts || []), cloneDepp(defaultSkill)];
      this.updateInputValue();
    },
    deleteConatct(key) {
      this.contacts = this.contacts?.filter((_, index) => index !== key) || [];
    },
    hideDropDowm(refName) {
      this.$refs[`${refName}`].at(0).hide();
    },
  },
  watch: {
    contacts() {
      this.setFormProperty(this.properties, [this.contacts]);
    },
    value: {
      immediate: true,
      handler() {
        this.contacts = this.value;
      },
    },
  },
};
</script>

