<template>
  <div
    class="title title-container position-relative py-2"
    style="width: 90%; margin-left: auto; margin-right: auto; margin-bottom: 50px"
    tabindex="-1"
    @blur="focus = false"
    @focus="onFocus()"
  >
  <div style="height: 2px; top: 25px;"
   :style="`border:1px solid ${currentColor.style}`"
    class="w-100 position-absolute">
  </div>
    <div
      class="position-relative"
      style="
        margin-left: auto;
        margin-right: auto;
        left: 0;
        right: 0;
        font-size: 32px;
        width: fit-content;
      "
    >
      <b-input
        :ref="refName"
        v-model="value"
        :placeholder="placeholder"
        @change="onChange"
        v-autowidth="{ maxWidth: '960px', minWidth, comfortZone: 0 }"
        :style="`font-size: 24px;
          font-weight: bold;
          border: none;
          text-align: center;
          padding: 0px 20px;
          margin: 0 auto;
          color: ${currentColor} !importnat;
          font-family: ${currentFont.name}, sans-serif !important;
          `"
        :class="`color-${currentColor.class}`"
      />
    </div>
  </div>
</template>

<script>
import { v4 as uuidv4 } from 'uuid';
import { mapMutations, mapState } from 'vuex';
import types from '@/store/modules/form/types';

const refName = `title-container-ref-${uuidv4()}`;
export default {
  name: 'TitleContainer',
  props: {
    id: {
      type: String,
      require: true,
    },
    text: {
      type: String,
      require: true,
    },
    placeholder: {
      type: String,
      require: true,
    },
  },
  data() {
    return {
      value: '',
      focus: false,
      refName,
    };
  },
  methods: {
    ...mapMutations('form', { updateTitleContainer: types.UPDATE_TITLE_CONTAINER }),
    onFocus() {
      this.focus = true;
      this.$refs[this.refName]?.focus();
    },
    onChange(value) {
      this.updateTitleContainer({ id: this.id, value });
    },
  },
  computed: {
    minWidth() {
      const text = this.value || this.placeholder;
      return `${text.length * 15}px`;
    },
    ...mapState('form', ['currentColor', 'currentFont']),
  },
  watch: {
    text: {
      immediate: true,
      handler() {
        this.value = this.text;
      },
    },
  },
};
</script>
