<template>
  <div class="base-icon-selector d-flex position-relative">
    <div class="icon-active">
      <b-icon
      :icon="inputValue" scale="1.5"
      :style="`color: ${currentColor.style}`"
      />
    </div>
    <div style="margin-left: 10px" v-if="!isStatic">
      <b-icon
        scale="1"
        icon="caret-down"
        @click="toggleIconList()"
        style="height: 30px; width: 20px"
      />
      <div
        v-if="showIconsList"
        class="icon-list position-absolute d-flex bg-white"
        style="left: -10px; z-index: 10"
      >
        <div
          v-for="icon in icons"
          :key="icon"
          class="border m-1 d-flex align-items-center justify-content-center"
          style="width: 30px; height: 30px"
          v-click-outside="() => setShowIconList(false)"
        >
          <b-icon :icon="icon" scale="1.5" @click="setActiveIcon(icon)" />
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { mapState } from 'vuex';

import ClickOutside from 'vue-click-outside';

const getCopyObject = (object) => JSON.parse(JSON.stringify(object));
const iconsDefault = ['phone', 'mailbox', 'geo-alt-fill', 'github'];

export default {
  name: 'BaseIconSelector',
  props: {
    value: {
      type: String,
      default: getCopyObject(iconsDefault).at(0),
    },
    isStatic: {
      type: Boolean,
      default: false,
    },
  },
  data() {
    return {
      inputValue: new Date(),
      icons: iconsDefault,
      showIconsList: false,
    };
  },
  computed: {
    ...mapState('form', ['currentColor']),
  },
  watch: {
    value: {
      immediate: true,
      handler: 'onUpdateValue',
    },
    inputValue: {
      immediate: true,
      handler: 'onUpdateInputValue',
    },
  },
  methods: {
    toggleIconList() {
      setTimeout(() => {
        this.setShowIconList(!this.showIconsList);
      }, 100);
    },
    setShowIconList(value) {
      this.showIconsList = value;
    },
    onUpdateValue() {
      if (!this.value) return;
      this.inputValue = this.value;
    },
    onUpdateInputValue(inputValue) {
      this.$emit('input', inputValue);
    },
    setActiveIcon(icon) {
      this.inputValue = icon;
      this.setShowIconList(false);
    },
  },
  directives: {
    ClickOutside,
  },
};
</script>
<style lang="scss" scoped></style>
