<!-- eslint-disable vuejs-accessibility/click-events-have-key-events -->
<template>
  <div
  class="focus-container"
    style="margin: 16px 0px;"
    tabindex="-1"
    @click="() => setFocus(true)"
    v-click-outside="() => setFocus(false)"
    >
      <div>
        <div>
          <div>
            <slot :isFocus="isActive" />
          </div>
        </div>
      </div>
  </div>
</template>

<script>
import ClickOutside from 'vue-click-outside';

export default {
  name: 'ContainerFocusItem',
  props: {
    name: {
      type: String,
      require: true,
      default: '',
    },
    isActive: {
      type: Boolean,
      default: false,
    },
  },
  data() {
    return {
      isFocus: false,
      classOnFocus: 'border shadow py-4 my-4 mb-2 bg-white rounded',
      classOnHover: 'border border-secondary bg-white rounded',
    };
  },
  computed: {
    actions() {
      return {
        [`${this.name}-on-focus`]: this.setFocus,
        [`${this.name}-on-blur`]: this.setUnfocus,
      };
    },
  },
  watch: {
    isFocus: {
      handler(isFocus) {
        const name = isFocus ? this.name : '';
        this.$emit('set-focus', name);
      },
    },
    isActive(isActive) {
      this.isFocus = isActive;
    },
  },
  methods: {
    setFocus(state) {
      this.isFocus = state;
    },
    getAction() {
      return {
        [`${this.name}-on-focus`]: this.setFocus,
        [`${this.name}-on-blur`]: this.setUnfocus,
      };
    },
    setUnfocus() {
      if (!this.isFocus) return;
      this.setFocus(false);
    },

  },
  directives: {
    ClickOutside,
  },
};
</script>

<style lang="scss" scoped>
  .border {
    transition: border-color .3s ease;
  }
  .border-style {
    border: 1px solid white
  }
  .border-primary {
    border-color: var(--bs-primary)
  }
  .border-secondary {
    border-color: var(--bs-secondary)
  }
</style>
